prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?start ?startName ?task ?taskName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2f572d235e784b838fa0d7d2a56748ab" ;
         tai:belongsTo ?org .
  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?definitions .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }

  FILTER NOT EXISTS {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  }
}
ORDER BY ?choreo ?taskName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?choreo WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2f572d235e784b838fa0d7d2a56748ab" ;
         tai:belongsTo ?org .
  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }
  FILTER(
    NOT EXISTS {
      ?start a bboExt:StartEvent ;
             tai:belongsTo ?choreo .
      ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
    }
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo 
       (COUNT(DISTINCT ?start) AS ?startCount)
       (COUNT(DISTINCT ?task) AS ?taskCount)
       (COUNT(DISTINCT ?reachableTask) AS ?reachableTaskCount)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2f572d235e784b838fa0d7d2a56748ab" ;
         tai:belongsTo ?org .
  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .

  OPTIONAL { ?start a bboExt:StartEvent ; tai:belongsTo ?choreo . }
  OPTIONAL {
    ?task a bboExt:ChoreographyTask ;
          tai:belongsTo ?choreo .
  }

  OPTIONAL {
    ?start a bboExt:StartEvent ;
           tai:belongsTo ?choreo .
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?reachableTask .
    ?reachableTask a bboExt:ChoreographyTask .
  }
}
GROUP BY ?choreo
ORDER BY DESC(?reachableTaskCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?task ?taskName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2f572d235e784b838fa0d7d2a56748ab" ;
         tai:belongsTo ?org .
  ?definitions tai:belongsTo ?model .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  OPTIONAL { ?task bbo:name ?taskName . }

  FILTER NOT EXISTS {
    ?start a bboExt:StartEvent ;
           tai:belongsTo ?choreo .
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?reachableTask .
    ?reachableTask a bboExt:ChoreographyTask ;
                    tai:belongsTo ?choreo .
    FILTER(?reachableTask = ?task)
  }
}
ORDER BY ?choreo ?taskName
LIMIT 25
